def validate(args, output):
    numCourses, prerequisites = args[0], args[1]
    # detect whether a valid ordering exists at all (cycle => none)
    from collections import defaultdict, deque
    adj = defaultdict(list)
    indeg = [0] * numCourses
    for a, b in prerequisites:
        adj[b].append(a)
        indeg[a] += 1
    q = deque([i for i in range(numCourses) if indeg[i] == 0])
    done = 0
    ind = indeg[:]
    while q:
        node = q.popleft()
        done += 1
        for nxt in adj[node]:
            ind[nxt] -= 1
            if ind[nxt] == 0:
                q.append(nxt)
    feasible = (done == numCourses)
    if not isinstance(output, list):
        return False
    if not feasible:
        return len(output) == 0
    # must be a permutation of 0..numCourses-1
    if sorted(output) != list(range(numCourses)):
        return False
    pos = {v: i for i, v in enumerate(output)}
    # every prerequisite b must come before course a
    for a, b in prerequisites:
        if pos[b] > pos[a]:
            return False
    return True

