function validate(args, output) {
    const numCourses = args[0], prerequisites = args[1];
    const adj = Array.from({length: numCourses}, () => []);
    const indeg = new Array(numCourses).fill(0);
    for (const [a, b] of prerequisites) { adj[b].push(a); indeg[a]++; }
    const ind = indeg.slice();
    const q = [];
    for (let i = 0; i < numCourses; i++) if (ind[i] === 0) q.push(i);
    let done = 0, head = 0;
    while (head < q.length) {
        const node = q[head++];
        done++;
        for (const nxt of adj[node]) { if (--ind[nxt] === 0) q.push(nxt); }
    }
    const feasible = (done === numCourses);
    if (!Array.isArray(output)) return false;
    if (!feasible) return output.length === 0;
    const sorted = output.slice().sort((x, y) => x - y);
    for (let i = 0; i < numCourses; i++) if (sorted[i] !== i) return false;
    const pos = new Array(numCourses);
    for (let i = 0; i < output.length; i++) pos[output[i]] = i;
    for (const [a, b] of prerequisites) { if (pos[b] > pos[a]) return false; }
    return true;
}

