def gen(rng, size):
    n = max(2, min(size, 200))
    perm = list(range(n))
    rng.shuffle(perm)
    rank = {perm[i]: i for i in range(n)}
    edges = []
    seen = set()
    m = rng.randint(0, n * 2)
    for _ in range(m):
        a, b = rng.sample(range(n), 2)
        if rank[a] < rank[b]:
            a, b = b, a
        if (a, b) not in seen and a != b:
            seen.add((a, b)); edges.append([a, b])
    return [n, edges]

