var findOrder = function(numCourses, prerequisites) {
    const adj = Array.from({length: numCourses}, () => []);
    const indeg = new Array(numCourses).fill(0);
    for (const [a, b] of prerequisites) { adj[b].push(a); indeg[a]++; }
    // min-heap over node ids for a canonical lexicographically-smallest order
    const heap = [];
    const up = (i) => { while (i > 0) { const p = (i - 1) >> 1; if (heap[p] <= heap[i]) break; [heap[p], heap[i]] = [heap[i], heap[p]]; i = p; } };
    const down = (i) => { const n = heap.length; for (;;) { let s = i, l = 2*i+1, r = 2*i+2; if (l < n && heap[l] < heap[s]) s = l; if (r < n && heap[r] < heap[s]) s = r; if (s === i) break; [heap[s], heap[i]] = [heap[i], heap[s]]; i = s; } };
    const push = (v) => { heap.push(v); up(heap.length - 1); };
    const pop = () => { const top = heap[0]; const last = heap.pop(); if (heap.length) { heap[0] = last; down(0); } return top; };
    for (let i = 0; i < numCourses; i++) if (indeg[i] === 0) push(i);
    const res = [];
    while (heap.length) {
        const u = pop();
        res.push(u);
        for (const v of adj[u]) { if (--indeg[v] === 0) push(v); }
    }
    return res.length === numCourses ? res : [];
};
